```sql
CREATE FUNCTION GetEmployeeSalary(EmployeeID INT)
RETURNS DECIMAL(10,2)
BEGIN
   DECLARE salary DECIMAL(10,2);
   SELECT Salary INTO salary FROM Employee WHERE ID = EmployeeID;
   RETURN salary;
END;
```
